#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
const int maxn = 5005, max2 = (1 << 20) + 5, MOD = 998244353;
int n, a[maxn], f[maxn][maxn];
ll fp(int p)
{
	if (p == 0)
	{
		return 1;
	}
	ll ans = fp(p >> 1);
	ans = (ans * ans) % MOD;
	if (p & 1)
	{
		ans = (ans << 1) % MOD;
	}
	return ans;
}
int main(void)
{
	cin >> n;
	for (int i = 1; i <= n; ++i)
	{
		cin >> a[i];
	}
	sort(a + 1, a + n + 1);
	int maxx = a[n];
	f[0][0] = 1;
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 0; j <= maxx; ++j)
		{
			if(j>=a[i])f[i][j] = (f[i - 1][j] + f[i - 1][j - a[i]]) % MOD;
            else f[i][j] = f[i - 1][j];
		}
	}
	ll ans = 0, sum = 0;
	for (int i = 3; i <= n; ++i)
	{
		sum = 0;
		for (int j = 0; j <= a[i]; ++j)
		{
			sum += f[i - 1][j];
			sum %= MOD;
		}
		ans = ((ans - sum + fp(i - 1)) % MOD + MOD) % MOD;
	}
	cout << ans ;
	return false;
}
